# Module defining geometric shapes and interfaces
interface IShape:
    def area(self) -> float: ...
    def perimeter(self) -> float: ...

interface IDrawable:
    def draw(self) -> str: ...

class Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

    @override
    def __str__(self) -> str:
        return f"Point({{self.x}}, {{self.y}})"

class Rectangle(IShape, IDrawable):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Rectangle({{self.width}} x {{self.height}})"

class Circle(IShape, IDrawable):
    radius: float
    PI: float = 3.14159

    def __init__(self, radius: float):
        self.radius = radius

    @override
    def area(self) -> float:
        return self.PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2 * self.PI * self.radius

    @override
    def draw(self) -> str:
        return f"Circle(r={{self.radius}})"

def create_unit_square() -> Rectangle:
    return Rectangle(1.0, 1.0)

def calculate_total(rect_area: float, circle_area: float) -> float:
    return rect_area + circle_area

