# Module extending geometry into 3D shapes
from geometry import Point, IShape

class Shape3D:
    center: Point

    def __init__(self, center: Point):
        self.center = center

    def volume(self) -> float:
        return 0.0

class Cube(Shape3D, IShape):
    side: float

    def __init__(self, center: Point, side: float):
        super().__init__(center)
        self.side = side

    @override
    def area(self) -> float:
        return 6 * self.side * self.side

    @override
    def volume(self) -> float:
        return self.side ** 3

class Sphere(Shape3D, IShape):
    radius: float

    def __init__(self, center: Point, radius: float):
        super().__init__(center)
        self.radius = radius

    @override
    def area(self) -> float:
        return 4 * 3.14159 * self.radius * self.radius

    @override
    def volume(self) -> float:
        return (4.0 / 3.0) * 3.14159 * self.radius ** 3

def origin() -> Point:
    return Point(0.0, 0.0)
